const input = $input.first().json;
const extractedText = input.extracted_text.join(" ");
const errorsAndCorrections = input.errors_and_corrections;

return [
  {
    json: {
      extractedText,
      errorsAndCorrections,
    },
  },
];

// n8n Code Node: Clean & Normalize OCR Output (embedded in code-fenced JSON)

function unwrapCodeFence(s = "") {
  // Extract JSON inside ```json ... ``` or ``` ... ```
  const fence = s.match(/```(?:json)?\s*([\s\S]*?)```/i);
  return fence ? fence[1].trim() : s.trim();
}

function safeParse(maybeJson) {
  try {
    return typeof maybeJson === "string" ? JSON.parse(maybeJson) : maybeJson;
  } catch (e) {
    throw new Error("Failed to parse embedded JSON: " + e.message);
  }
}

function cleanTextArray(arr) {
  if (!Array.isArray(arr)) return [];
  // Trim, remove empties, normalize spaces, and dedupe while preserving order
  const seen = new Set();
  const out = [];
  for (const v of arr) {
    if (typeof v !== "string") continue;
    const t = v.replace(/\s+/g, " ").trim();
    if (!t) continue;
    if (!seen.has(t)) {
      seen.add(t);
      out.push(t);
    }
  }
  return out;
}

function countByType(errors) {
  const byType = {};
  for (const e of errors) {
    const t = (e?.error_type || "Unknown").trim();
    byType[t] = (byType[t] || 0) + 1;
  }
  return byType;
}

// 1) Collect raw text payloads from all incoming items (if multiple)
const items = $input.all();
let combinedText = "";

for (const item of items) {
  // Your sample structure: item.json.content.parts[].text
  const parts = item?.json?.content?.parts;
  if (Array.isArray(parts)) {
    for (const p of parts) {
      if (typeof p?.text === "string") combinedText += "\n" + p.text;
    }
  } else {
    // fallback: accept raw json or text in item.json
    const possible = item?.json?.text || item?.json?.data || item?.json;
    if (typeof possible === "string") combinedText += "\n" + possible;
  }
}

// 2) Unwrap code fence and parse JSON
const unwrapped = unwrapCodeFence(combinedText);
const parsed = safeParse(unwrapped);

// 3) Normalize extracted_text
const extracted_text = cleanTextArray(parsed?.extracted_text);

// 4) Keep errors as-is, ensure it's an array
const errors_and_corrections = Array.isArray(parsed?.errors_and_corrections)
  ? parsed.errors_and_corrections
  : [];

// 5) Totals
const totals = {
  total_text_items: extracted_text.length,
  total_errors: errors_and_corrections.length,
  by_type: countByType(errors_and_corrections),
};

// 6) Pass-through original summary if present
const original_summary = parsed?.summary || null;

// 7) Final cleaned output
return [
  {
    json: {
      extracted_text,
      total_text_items: totals.total_text_items,
      errors_and_corrections,
      totals,
      original_summary,
    },
  },
];

// Combine all incoming data into a single output object

let combinedData = {
  text: [],
  errors: [],
  image: []
};

for (const item of items) {
  if (item.json) {
    if (item.json.extractedText) combinedData.text.push(item.json.extractedText);
    if (item.json.errorsAndCorrections) combinedData.errors.push(item.json.errorsAndCorrections);
    if (item.json.databinary) combinedData.image.push(item.json.databinary);
  }
}

// Just send the first image/text/errors if there’s only one
return [
  {
    json: {
      text: combinedData.text[0] || null,
      errors: combinedData.errors[0] || [],
      image: combinedData.image[0] || null
    }
  }
];

let output = {
  image: null,
  errors: [],
   text: ""
};

for (const item of items) {
   if (item.json.text) output.text = item.json.text;
  if (item.json.errors) output.errors = item.json.errors;
  if (item.json.image) output.image = item.json.image;
}

return [{ json: output }];

// n8n Code Node - Extract errors + coordinates and produce compact highlight prompt

const inputData = $input.all();

// Utility: normalize text for comparison
function normalize(s) {
  if (!s) return '';
  return s
    .toString()
    .replace(/\s+/g, ' ')
    .replace(/[“”"']/g, '')
    .replace(/[^\w\s]/g, '')
    .trim()
    .toLowerCase();
}

// Normalize bounding box formats into {x,y,w,h}
// Accepts forms: {x,y,w,h} or {left,top,width,height} or [x1,y1,x2,y2]
function normalizeBox(box) {
  if (!box) return null;
  if (Array.isArray(box) && box.length === 4) {
    const [x1, y1, x2, y2] = box;
    return { x: x1, y: y1, w: x2 - x1, h: y2 - y1 };
  }
  if (box.x !== undefined && box.y !== undefined && box.w !== undefined && box.h !== undefined) {
    return { x: box.x, y: box.y, w: box.w, h: box.h };
  }
  if (box.left !== undefined && box.top !== undefined && box.width !== undefined && box.height !== undefined) {
    return { x: box.left, y: box.top, w: box.width, h: box.height };
  }
  // try other common property names
  if (box.x1 !== undefined && box.y1 !== undefined && box.x2 !== undefined && box.y2 !== undefined) {
    return { x: box.x1, y: box.y1, w: box.x2 - box.x1, h: box.y2 - box.y1 };
  }
  return null;
}

// Merge multiple boxes (array of {x,y,w,h}) into a bounding box
function mergeBoxes(boxes) {
  if (!boxes || boxes.length === 0) return null;
  let x1 = Infinity, y1 = Infinity, x2 = -Infinity, y2 = -Infinity;
  for (const b of boxes) {
    if (!b) continue;
    x1 = Math.min(x1, b.x);
    y1 = Math.min(y1, b.y);
    x2 = Math.max(x2, b.x + b.w);
    y2 = Math.max(y2, b.y + b.h);
  }
  return { x: x1, y: y1, w: x2 - x1, h: y2 - y1 };
}

// Try to locate phrase in OCR tokens
// Assumes tokens = [{text, bbox}] where bbox can be various formats
function findCoordsByPhrase(phrase, tokens) {
  if (!phrase || !tokens || tokens.length === 0) return null;

  const normPhrase = normalize(phrase);
  const phraseWords = normPhrase.split(' ').filter(Boolean);

  // Build normalized tokens array and their boxes
  const normTokens = tokens.map(t => ({
    text: (t.text || t.word || t.value || '').toString(),
    norm: normalize(t.text || t.word || t.value || ''),
    bbox: normalizeBox(t.bbox || t.box || t.boundingBox || t.coords || t.poly)
  }));

  // 1) Try exact contiguous token sequence match
  for (let i = 0; i <= normTokens.length - phraseWords.length; i++) {
    let match = true;
    const matchedBoxes = [];
    for (let j = 0; j < phraseWords.length; j++) {
      if (normTokens[i + j].norm !== phraseWords[j]) {
        match = false;
        break;
      }
      matchedBoxes.push(normTokens[i + j].bbox);
    }
    if (match) {
      const merged = mergeBoxes(matchedBoxes.filter(Boolean));
      if (merged) return merged;
    }
  }

  // 2) Try substring scanning: token.norm contains phrase
  for (const t of normTokens) {
    if (!t.norm) continue;
    if (t.norm.includes(normPhrase) || normPhrase.includes(t.norm)) {
      if (t.bbox) return t.bbox;
    }
  }

  // 3) Fuzzy: count overlapping words and take highest match
  let best = { score: 0, boxes: [] };
  for (let i = 0; i < normTokens.length; i++) {
    let score = 0;
    const boxes = [];
    for (let j = 0; j < phraseWords.length && (i + j) < normTokens.length; j++) {
      if (normTokens[i + j].norm === phraseWords[j]) {
        score++;
        boxes.push(normTokens[i + j].bbox);
      } else if ((normTokens[i + j].norm || '').includes(phraseWords[j]) || phraseWords[j].includes((normTokens[i + j].norm || ''))) {
        score += 0.5;
        boxes.push(normTokens[i + j].bbox);
      } else {
        // allow small gaps but break if long mismatch
        if (j > 2) break;
      }
    }
    if (score > best.score) {
      best.score = score;
      best.boxes = boxes;
    }
  }
  if (best.score > 0) {
    const merged = mergeBoxes(best.boxes.filter(Boolean));
    if (merged) return merged;
  }

  // No coordinate found
  return null;
}

// Map error types to colors
const colorMap = {
  'Spelling': 'red',
  'Grammar': 'blue',
  'Typo': 'green',
  'Punctuation': 'orange',
  'Spacing' : 'brown',
  'Consistency': 'purple'
};

const outputItems = inputData.map(item => {
  const jsonData = item.json;
  const data = Array.isArray(jsonData) ? jsonData[0] : jsonData || {};

  // Attempt to find OCR tokens in various likely keys
  const ocrCandidates = [
    data.ocrTokens,
    data.ocr,
    data.tokens,
    data.extractedTokens,
    data.textTokens,
    data.words,
    data.lines
  ].filter(Boolean);

  // Flatten tokens if nested
  let tokens = [];
  if (ocrCandidates.length) {
    // if some candidate is an array take the first non-empty
    const candidate = ocrCandidates.find(c => Array.isArray(c) && c.length > 0) || ocrCandidates[0];
    tokens = Array.isArray(candidate) ? candidate : [];
  }

  const errors = data.errorsAndCorrections || data.errors || [];

  const errors_extracted = errors.map(err => {
    const found_text = err.found_text || err.text || err.incorrect || err.original || '';
    const corrected_text = err.corrected_text || err.correction || err.suggested || '';
    const issue_description = err.issue_description || err.note || '';
    const error_type = err.error_type || err.type || 'Unknown';
    const id = err.error_id || err.id || null;

    // 1) If coordinates present on the error item use them
    const possibleBox = normalizeBox(err.coords || err.bbox || err.box || err.boundingBox || err.coordinates);
    let coords = possibleBox || null;

    // 2) If not present, attempt to find in tokens
    if (!coords && tokens && tokens.length > 0) {
      const found = findCoordsByPhrase(found_text, tokens);
      coords = found;
    }

    // 3) Normalize coords to null if invalid
    if (coords && (!isFinite(coords.x) || !isFinite(coords.y) || !isFinite(coords.w) || !isFinite(coords.h))) {
      coords = null;
    }

    return {
      error_id: id,
      found_text,
      corrected_text,
      issue_description,
      error_type,
      color: colorMap[error_type] || 'yellow',
      coords // {x,y,w,h} or null
    };
  });

  // Build short editor prompt
  // If all have coords -> concise coordinate-based instructions
  const allHaveCoords = errors_extracted.every(e => e.coords);
  let editor_prompt = '';
  if (errors_extracted.length === 0) {
    editor_prompt = 'No errors found in input.';
  } else if (allHaveCoords) {
    editor_prompt = 'Highlight the following words using the given coordinates and color (format: x,y,w,h,color,label):\n';
    editor_prompt += errors_extracted.map(e => {
      return `${Math.round(e.coords.x)},${Math.round(e.coords.y)},${Math.round(e.coords.w)},${Math.round(e.coords.h)},${e.color},#${e.error_id || 'NA'},"${e.found_text}"`;
    }).join('\n');
  } else {
    // Mixed or no coords: instruct a hybrid approach
    editor_prompt = 'For each item below, either use the provided coordinates to highlight the word, or locate and highlight the exact phrase in the image text if coordinates are null.\n\n';
    editor_prompt += errors_extracted.map(e => {
      if (e.coords) {
        return `#${e.error_id || 'NA'}: "${e.found_text}" — COORDS: ${Math.round(e.coords.x)},${Math.round(e.coords.y)},${Math.round(e.coords.w)},${Math.round(e.coords.h)} — COLOR: ${e.color}`;
      } else {
        return `#${e.error_id || 'NA'}: "${e.found_text}" — COORDS: null — Please find the exact phrase and highlight it — COLOR: ${e.color}`;
      }
    }).join('\n');
  }

  return {
    json: {
      errors_extracted,
      total_errors: errors_extracted.length,
      all_have_coords: allHaveCoords,
      editor_prompt
    }
  };
});

return outputItems;
